SELECT * FROM store_sales sts, store_returns sr, date_dim, web_sales ws, web_returns wr, catalog_sales cs, catalog_returns cr WHERE sr.sr_return_amt > 10000 AND sts.ss_net_profit > 1 AND sts.ss_net_paid > 0 AND sts.ss_quantity > 0 AND ss_sold_date_sk = d_date_sk AND d_year = 1998 AND d_moy = 11 AND wr.wr_return_amt > 10000 AND ws.ws_net_profit > 1 AND ws.ws_net_paid > 0 AND ws.ws_quantity > 0 AND ws_sold_date_sk = d_date_sk AND cr.cr_return_amount > 10000 AND cs.cs_net_profit > 1 AND cs.cs_net_paid > 0 AND cs.cs_quantity > 0 AND cs_sold_date_sk = d_date_sk AND (sts.ss_ticket_number = sr.sr_ticket_number AND sts.ss_item_sk = sr.sr_item_sk) AND (ws.ws_order_number = wr.wr_order_number AND ws.ws_item_sk = wr.wr_item_sk) AND (cs.cs_order_number = cr.cr_order_number AND cs.cs_item_sk = cr.cr_item_sk);
